import { useState, useCallback } from "react";
import { useTranslation } from "react-i18next";
import { Search, Shuffle, Loader2, Clock, Users, ChefHat, Sparkles, Globe } from "lucide-react";
import { Input } from "@/components/ui/input";
import { Button } from "@/components/ui/button";
import { supabase } from "@/integrations/supabase/client";
import { AIRecipeSuggestion } from "@/hooks/useAIRecipe";
import SavedRecipeDetailDialog from "@/components/ai-recipe/SavedRecipeDetailDialog";
import { useSavedRecipes } from "@/hooks/useSavedRecipes";
import { useAuth } from "@/contexts/AuthContext";
import { toast } from "sonner";

const AIVideoGenerator = () => {
  const { t, i18n } = useTranslation();
  const { user } = useAuth();
  const { saveRecipe, isSaving, savedRecipes } = useSavedRecipes();

  const [searchTerm, setSearchTerm] = useState("");
  const [isSearching, setIsSearching] = useState(false);
  const [isRandom, setIsRandom] = useState(false);
  const [results, setResults] = useState<Array<{ recipe: AIRecipeSuggestion; name: string; imageUrl: string | null }>>([]);
  const [selectedRecipe, setSelectedRecipe] = useState<AIRecipeSuggestion | null>(null);
  const [selectedName, setSelectedName] = useState("");
  const [selectedImageUrl, setSelectedImageUrl] = useState<string | null>(null);
  const [dialogOpen, setDialogOpen] = useState(false);

  const isSaved = selectedRecipe
    ? savedRecipes.some((r) => r.recipe_name === selectedRecipe.recipe_name)
    : false;

  const parseRecipeData = (row: any): AIRecipeSuggestion | null => {
    try {
      const data = typeof row.recipe_data === "string" ? JSON.parse(row.recipe_data) : row.recipe_data;
      return {
        ...data,
        recipe_name: row.recipe_name || data.recipe_name,
        recipe_name_en: row.recipe_name_en || data.recipe_name_en,
        recipe_name_pt: row.recipe_name_pt || data.recipe_name_pt,
        image_url: row.image_url || data.image_url,
        image_source: row.image_source || data.image_source,
        difficulty: row.difficulty || data.difficulty,
        servings: row.servings || data.servings,
      };
    } catch {
      return null;
    }
  };

  const handleSearch = useCallback(async () => {
    const term = searchTerm.trim();
    if (!term) return;
    setIsSearching(true);
    setIsRandom(false);
    try {
      // First try local cache
      const { data, error } = await supabase
        .from("ai_recipe_cache")
        .select("*")
        .or(`recipe_name.ilike.%${term}%,recipe_name_en.ilike.%${term}%,recipe_name_pt.ilike.%${term}%`)
        .eq("is_approved", true)
        .limit(10);

      if (error) throw error;

      if (data && data.length > 0) {
        const parsed = data.map(row => {
          const recipe = parseRecipeData(row);
          return recipe ? { recipe, name: row.recipe_name, imageUrl: row.image_url } : null;
        }).filter(Boolean) as Array<{ recipe: AIRecipeSuggestion; name: string; imageUrl: string | null }>;

        if (parsed.length > 0) {
          toast.success(t("aiRecipe.videoGen.found"));
          setResults(parsed);
          return;
        }
      }

      // Not found in cache — call AI to generate
      toast.info(t("aiRecipe.videoGen.generating", "未找到缓存，AI 正在为您生成..."));
      const { data: fnData, error: fnError } = await supabase.functions.invoke("ai-recipe/lookup-dish", {
        body: { dish_name: term, language: i18n.language },
      });

      if (fnError) throw fnError;
      if (fnData?.error) throw new Error(fnData.error);

      const recipe = fnData?.recipe as AIRecipeSuggestion | undefined;
      if (!recipe || !recipe.recipe_name) {
        toast.error(t("aiRecipe.videoGen.error"));
        setResults([]);
        return;
      }

      toast.success(t("aiRecipe.videoGen.generated", "AI 已为您生成新食谱！"));
      setResults([{
        recipe,
        name: recipe.recipe_name,
        imageUrl: recipe.image_url || null,
      }]);
    } catch (err) {
      console.error("Search error:", err);
      toast.error(t("aiRecipe.videoGen.error"));
    } finally {
      setIsSearching(false);
    }
  }, [searchTerm, t, i18n.language]);

  const handleRandom = useCallback(async () => {
    setIsRandom(true);
    setIsSearching(true);
    try {
      const { count } = await supabase
        .from("ai_recipe_cache")
        .select("*", { count: "exact", head: true })
        .eq("is_approved", true);

      if (!count || count === 0) {
        toast.error(t("aiRecipe.videoGen.error"));
        return;
      }

      const randomOffset = Math.floor(Math.random() * count);
      const { data, error } = await supabase
        .from("ai_recipe_cache")
        .select("*")
        .eq("is_approved", true)
        .range(randomOffset, randomOffset)
        .limit(1)
        .maybeSingle();

      if (error) throw error;
      if (!data) {
        toast.error(t("aiRecipe.videoGen.error"));
        return;
      }
      const recipe = parseRecipeData(data);
      if (!recipe) {
        toast.error(t("aiRecipe.videoGen.error"));
        return;
      }
      toast.success(t("aiRecipe.videoGen.found"));
      setResults([{ recipe, name: data.recipe_name, imageUrl: data.image_url }]);
    } catch (err) {
      console.error("Random pick error:", err);
      toast.error(t("aiRecipe.videoGen.error"));
    } finally {
      setIsSearching(false);
      setIsRandom(false);
    }
  }, [t]);

  const handleCardClick = (item: { recipe: AIRecipeSuggestion; name: string; imageUrl: string | null }) => {
    setSelectedRecipe(item.recipe);
    setSelectedName(item.name);
    setSelectedImageUrl(item.imageUrl);
    setDialogOpen(true);
  };

  const handleSave = async (recipe: AIRecipeSuggestion) => {
    if (!user) return;
    await saveRecipe(recipe);
  };

  const getRecipeDisplayName = (recipe: AIRecipeSuggestion, fallback: string) => {
    if (i18n.language === "en" && recipe.recipe_name_en) return recipe.recipe_name_en;
    if (i18n.language === "pt" && recipe.recipe_name_pt) return recipe.recipe_name_pt;
    return recipe.recipe_name || fallback;
  };

  const getDifficultyLabel = (d: string) => {
    switch (d) {
      case "easy": return t("recipe.difficulty.easy", "简单");
      case "medium": return t("recipe.difficulty.medium", "中等");
      case "hard": return t("recipe.difficulty.hard", "困难");
      default: return d;
    }
  };

  return (
    <div className="space-y-3">
      {/* Search bar */}
      <div className="flex gap-2">
        <div className="relative flex-1">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
          <Input
            placeholder={t("aiRecipe.videoGen.placeholder")}
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
            onKeyDown={(e) => e.key === "Enter" && handleSearch()}
            className="pl-9"
            disabled={isSearching}
          />
        </div>
        <Button
          onClick={handleSearch}
          disabled={isSearching || !searchTerm.trim()}
          size="sm"
          className="shrink-0"
        >
          {isSearching && !isRandom ? (
            <Loader2 className="h-4 w-4 animate-spin" />
          ) : (
            <Search className="h-4 w-4" />
          )}
        </Button>
        <Button
          variant="outline"
          onClick={handleRandom}
          disabled={isSearching}
          size="sm"
          className="shrink-0 gap-1.5"
        >
          {isRandom ? (
            <Loader2 className="h-4 w-4 animate-spin" />
          ) : (
            <Shuffle className="h-4 w-4" />
          )}
          <span className="hidden sm:inline">{t("aiRecipe.videoGen.random")}</span>
        </Button>
      </div>

      {results.length === 0 && (
        <p className="text-xs text-muted-foreground text-center">
          {t("aiRecipe.videoGen.placeholderHint")}
        </p>
      )}

      {/* Result cards */}
      {results.length > 0 && (
        <div className="grid gap-2">
          {results.map((item, idx) => {
            const name = getRecipeDisplayName(item.recipe, item.name);
            return (
              <button
                key={idx}
                onClick={() => handleCardClick(item)}
                className="flex items-center gap-3 p-3 rounded-xl border border-border hover:border-primary hover:bg-primary/5 transition-all text-left group"
              >
                {item.imageUrl ? (
                  <img
                    src={item.imageUrl}
                    alt={name}
                    className="w-16 h-16 rounded-lg object-cover shrink-0"
                  />
                ) : (
                  <div className="w-16 h-16 rounded-lg bg-muted flex items-center justify-center shrink-0">
                    <ChefHat className="h-6 w-6 text-muted-foreground" />
                  </div>
                )}
                <div className="flex-1 min-w-0 space-y-1">
                  <h4 className="font-medium text-sm truncate group-hover:text-primary transition-colors">{name}</h4>
                  <div className="flex items-center gap-3 text-xs text-muted-foreground">
                    {item.recipe.cook_time && (
                      <span className="flex items-center gap-1">
                        <Clock className="h-3 w-3" />
                        {item.recipe.cook_time}{t("recipe.minutes", "分钟")}
                      </span>
                    )}
                    {item.recipe.difficulty && (
                      <span>{getDifficultyLabel(item.recipe.difficulty)}</span>
                    )}
                    {item.recipe.servings && (
                      <span className="flex items-center gap-1">
                        <Users className="h-3 w-3" />
                        {item.recipe.servings}
                      </span>
                    )}
                  </div>
                </div>
              </button>
            );
          })}
        </div>
      )}

      {/* Recipe detail dialog */}
      <SavedRecipeDetailDialog
        open={dialogOpen}
        onOpenChange={setDialogOpen}
        recipe={selectedRecipe}
        recipeName={selectedRecipe ? getRecipeDisplayName(selectedRecipe, selectedName) : selectedName}
        onSave={user ? handleSave : undefined}
        isSaving={isSaving}
        isSaved={isSaved}
        initialImageUrl={selectedImageUrl}
        enableVideoGeneration={false}
      />
    </div>
  );
};

export default AIVideoGenerator;
